import { Command } from 'cmdk';
import { type JSX, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Icons, ICON_SIZE } from '@bim-ai/ui';
import {
  EMPTY_STATE_HINTS,
  parseQuery,
  rankCandidates,
  type CommandCandidate,
} from './commandPaletteSources';

/**
 * Redesigned command palette — spec §18.
 *
 * Wraps cmdk with the `commandPaletteSources` aggregator so the spec'd
 * `>`, `@`, `:` prefix grammar drives source filtering, and recent-id
 * boost lifts repeat actions to the top.
 *
 * Visual layout matches §18: 560 px wide, --radius-xl, --elev-3 shadow,
 * empty-state shows the top 5 keyboard hints.
 */

export interface CommandPaletteProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  /** Aggregated source list. The component is purely presentational —
   * callers compose tools / views / elements / settings / agent actions
   * into a flat candidate array. */
  candidates: CommandCandidate[];
  /** Recent action ids (most recent first). Capped at 5 internally. */
  recentIds?: string[];
  /** Invoked when the user picks a candidate (`Enter` or click). */
  onPick: (candidate: CommandCandidate) => void;
}

export function CommandPalette({
  open,
  onOpenChange,
  candidates,
  recentIds,

class TestMissingAssumptions:
    def test_empty_assumptions_rejected(self):
        doc = _seed_doc()
        bundle = CommandBundle.model_validate({
            "schemaVersion": "cmd-v3.0",
            "commands": [_CREATE_LEVEL],
            "assumptions": [_VALID_ASSUMPTION],  # Pydantic requires min_length=1
            "parentRevision": 1,
        })
        # Force empty by bypassing validation
        object.__setattr__(bundle, "assumptions", [])
        result = apply_bundle(doc, bundle, "dry_run")
        classes = {v.get("advisoryClass") for v in result.violations}
        assert "assumption_log_required" in classes
        assert result.applied is False

    def test_duplicate_key_rejected(self):
        doc = _seed_doc()
        dup = [_VALID_ASSUMPTION, {**_VALID_ASSUMPTION}]
        bundle = _bundle(assumptions=dup)
        result = apply_bundle(doc, bundle, "dry_run")
        classes = {v.get("advisoryClass") for v in result.violations}
        assert "assumption_log_duplicate_key" in classes
        assert result.applied is False


class TestRevisionGuard:
    def test_stale_revision_rejected(self):
        doc = _seed_doc(revision=5)
        bundle = _bundle(parentRevision=3)
        result = apply_bundle(doc, bundle, "dry_run")
        classes = {v.get("advisoryClass") for v in result.violations}
        assert "revision_conflict" in classes
        assert result.applied is False

    def test_matching_revision_accepted(self):
        doc = _seed_doc(revision=5)
        bundle = _bundle(parentRevision=5)
        result = apply_bundle(doc, bundle, "commit")
        assert result.applied is True


class TestTargetOptionId:
    def test_main_always_rejected(self):
        doc = _seed_doc()
        bundle = _bundle(targetOptionId="main")
        result = apply_bundle(doc, bundle, "commit")
        classes = {v.get("advisoryClass") for v in result.violations}
        assert "direct_main_commit_forbidden" in classes
        assert result.applied is False

    def test_non_main_option_id_rejected_with_not_implemented(self):
        doc = _seed_doc()
        bundle = _bundle(targetOptionId="opt-123")
        result = apply_bundle(doc, bundle, "commit")
        classes = {v.get("advisoryClass") for v in result.violations}
        assert "option_routing_not_yet_implemented" in classes
        assert result.applied is False

def document_to_wire(doc: Document) -> dict[str, Any]:
    return {
        "revision": doc.revision,
        "elements": {kid: elem.model_dump(by_alias=True) for kid, elem in doc.elements.items()},
    }


def _commands_include_move_level_elevation(cmds: list[dict[str, Any]]) -> bool:
    return any(str(c.get("type") or "") == "moveLevelElevation" for c in cmds)

